/**
 * n8n Code node — place after Webhook. Normalizes POST JSON body.
 * Handles n8n shapes: body object, stringified JSON, top-level fields, or nested data/json.
 */
function pickPayload(root) {
  let raw = root?.body ?? root?.data ?? root?.json ?? root;
  if (typeof raw === 'string') {
    try {
      raw = JSON.parse(raw);
    } catch {
      throw new Error('Webhook body must be JSON with title and context');
    }
  }
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
    throw new Error('Invalid webhook payload: expected JSON object with title and context');
  }
  return raw;
}

const b = pickPayload($json);
const title = String(b.title ?? '').trim();
const context = String(b.context ?? '').trim();
const cover_image_url = String(b.cover_image_url ?? b.coverImageUrl ?? '').trim();
if (!title) throw new Error('title is required');
if (!context) throw new Error('context is required');
return [{ json: { title, context, cover_image_url } }];

/**
 * n8n Code node — place after "Normalize input". Calls Claude Messages API only.
 * Env:
 *   ANTHROPIC_API_KEY   — required
 *   ANTHROPIC_MODEL     — optional, default claude-sonnet-4-20250514
 * Sync with prompts in automation/n8n/prompts/openai-blog-system.txt
 */
function stripJsonFence(s) {
  let t = String(s || '').trim();
  t = t.replace(/^```(?:json)?\s*/i, '');
  t = t.replace(/\s*```$/i, '');
  return t.trim();
}

// Keep aligned with automation/n8n/prompts/openai-blog-system.txt
const SYSTEM = `You are an editor for a Canada-focused travel and culture blog (CitizenReady).

CRITICAL: The user message includes a Title hint and a Context block. Write the article ONLY from that Context. Expand, organize, and polish the ideas already in the Context. Do not switch to unrelated Canadian topics, places, or stories. Do not replace the user's topic with generic "Canada travel" filler. If the Context is brief, stay on that topic and develop it sensibly rather than inventing a different theme.

Rules:
- Every section must clearly follow from the supplied Context. Title and excerpt must match this specific topic.
- Keep content appropriate for Canada-focused readers (travel, cities, culture, etc.) only as it fits the Context.
- Warm, informative tone. No clickbait. If unsure of a fact, qualify it or avoid inventing statistics.
- Output ONLY valid JSON (no markdown fences). Schema:
{
  "title": "string, compelling and specific",
  "slug": "optional string, lowercase hyphenated; may be omitted",
  "excerpt": "string, max 300 chars, summary for listings",
  "cover_image": "optional absolute https URL if user did not supply one and you suggest a placeholder from a reputable free stock/CDN — only https URLs",
  "publish": true,
  "blocks": [
    { "type": "h2", "text": "Section title" },
    { "type": "paragraph", "text": "Body ..." },
    { "type": "image", "src": "https://...", "alt": "...", "layout": "center_large" }
  ]
}
- Include at least 3 h2 sections and several paragraphs. You may add one or two h3s where useful.
- blocks must represent the full article in reading order.`;

const input = $json;
const userMessage = `Write the full blog post using ONLY the information and angle below.

Title hint: ${input.title}

Context — sole source for topics, facts, and emphasis (stay faithful):
${input.context}

Optional cover image URL (use in output when provided): ${input.cover_image_url || 'none'}`;

const key = String($env.ANTHROPIC_API_KEY || '').trim();
if (!key) throw new Error('ANTHROPIC_API_KEY is required');
const model = String($env.ANTHROPIC_MODEL || 'claude-sonnet-4-20250514').trim();

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': key,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json',
  },
  body: {
    model,
    max_tokens: 8192,
    temperature: 0.35,
    system: SYSTEM,
    messages: [{ role: 'user', content: userMessage }],
  },
  json: true,
});

const block = Array.isArray(res.content) ? res.content.find((c) => c.type === 'text') : null;
const llmJsonText = stripJsonFence(block?.text);
if (!llmJsonText) throw new Error('Claude response missing text content');

return [
  {
    json: {
      llmJsonText,
      _llmProvider: 'anthropic',
    },
  },
];

/**
 * n8n Code node — run once per item, after "LLM (Claude)".
 * Input item 0: { llmJsonText } from call-llm-claude.js
 * Form fields: node FORM_NODE (webhook normalize).
 */
const FORM_NODE = 'Normalize input';

function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 96);
}

function blocksToTiptap(blocks) {
  const content = [];
  for (const b of blocks || []) {
    if (!b || !b.type) continue;
    const t = String(b.text || '').trim();
    if (!t && b.type !== 'paragraph') continue;
    if (b.type === 'h1') {
      content.push({
        type: 'heading',
        attrs: { level: 1 },
        content: [{ type: 'text', text: t }],
      });
    } else if (b.type === 'h2') {
      content.push({
        type: 'heading',
        attrs: { level: 2 },
        content: [{ type: 'text', text: t }],
      });
    } else if (b.type === 'h3') {
      content.push({
        type: 'heading',
        attrs: { level: 3 },
        content: [{ type: 'text', text: t }],
      });
    } else if (b.type === 'paragraph') {
      content.push({
        type: 'paragraph',
        content: t ? [{ type: 'text', text: t }] : [],
      });
    } else if (b.type === 'image' && b.src) {
      content.push({
        type: 'image',
        attrs: {
          src: String(b.src),
          alt: b.alt ? String(b.alt) : null,
          title: null,
          layout: b.layout || 'center_large',
        },
      });
    }
  }
  return { type: 'doc', content };
}

const form = $(FORM_NODE).first().json;
const raw = items[0].json?.llmJsonText;
if (!raw || typeof raw !== 'string') {
  throw new Error('Expected llmJsonText from LLM node');
}

let ai;
try {
  ai = JSON.parse(raw);
} catch {
  throw new Error(`Model did not return valid JSON. First 300 chars: ${raw.slice(0, 300)}`);
}

const title = String(ai.title || form.title || '').trim();
const slug = slugify(ai.slug || title);
const excerpt = String(ai.excerpt || '').trim().slice(0, 300);
const coverFromForm = String(form.cover_image_url || '').trim();
const coverFromAi = String(ai.cover_image || '').trim();
const cover_image = coverFromForm || coverFromAi || null;

const content = blocksToTiptap(ai.blocks);

/** Payload written to Drive + consumed by sync workflow */
const blogDraft = {
  title,
  slug,
  excerpt: excerpt || null,
  cover_image,
  content,
  /** Sync workflow maps this to Supabase status */
  publish: ai.publish !== false,
  source: 'n8n',
  generated_at: new Date().toISOString(),
};

return [{ json: blogDraft }];

const slug = String($json.slug || 'post').replace(/[^a-z0-9-]/gi, '-');
const fileName = `blog-${slug}-${Date.now()}.json`;
const jsonStr = JSON.stringify($json, null, 2);
const buf = Buffer.from(jsonStr, 'utf8');
const bin = await this.helpers.prepareBinaryData(buf, fileName, 'application/json');
return [{ json: $json, binary: { data: bin } }];
